ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?name WHERE {
  ?s a :Stories .
  ?j a :News_Agency .
  ?s p:hasnews_agencies ?j .
  ?j p:name ?name .
  ?s p:title ?title_f .
  FILTER(STR(?title_f) = "US Election Results")
} }
  component_2: { SELECT ?name WHERE {
  ?s a :Stories .
  ?j a :Journalists .
  ?s p:hasjournalists ?j .
  ?j p:name ?name .
  ?s p:title ?title_f .
  FILTER(STR(?title_f) = "US Election Results")
} }
  full: { SELECT ?name ?name2 WHERE {
  ?s a :Stories .
  ?j a :Journalists .
  ?s p:hasjournalists ?j .
  ?na a :News_Agency .
  ?s p:hasnews_agencies ?na .
  ?j p:name ?name .
  ?na p:name ?name2 .
  ?s p:title ?title_f .
  FILTER(STR(?title_f) = "US Election Results")
} }
}

